// Collect all generated image URLs
const items = $input.all();
const imageUrls = items.map((item, index) => ({
  slide: index + 1,
  image_url: item.json.image_url || item.json.url || 'pending',
  status: item.json.status || 'generated'
}));

return [{ json: { slides: imageUrls, total: imageUrls.length } }];
